var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"쿨럭 쿨럭!","JPN":"ゲホッ、ゲホッ！","ENG":"*Cough* *Cough*","TWN":"咳咳！咳咳！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"설마... 자폭한 거야…?","JPN":"まさか……自爆したの……？","ENG":"Did she... self-destruct...?","TWN":"難道……是自爆了…？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"저, 정말 죽어버렸다고?!","JPN":"ほ、本当に死んじゃったのか！？","ENG":"S-she's really dead?!","TWN":"什麼？瑪卡死了？！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"그럴리가…!","JPN":"そんな……！","ENG":"That can't be...!","TWN":"怎麼可能…！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"침식체들이 아직 남아있다! 슬퍼하고 있을 틈이 없어!","JPN":"侵食体がまだ残っている！　悲しんでいる暇はない！","ENG":"There are still C.O.s remaining! We can mourn for her later!","TWN":"侵蝕體還在！先振作起來！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"우리들만으로 저걸 전부 토벌하는 건 불가능해!","JPN":"私たちだけであれを全部討伐するのは不可能だ！","ENG":"It's impossible for us to kill them all!","TWN":"光靠我們怎麼可能殺得死那些東西！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그렇게 무서우면 도망치면 되잖냐.","JPN":"そんに怖いなら、逃げればいいではないか。","ENG":"If you're that scared, you should run.","TWN":"害怕的話就逃跑吧！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"내가 최대한 시간을 벌어볼 테니, 어서 마을을 떠나든가 해라.","JPN":"俺ができるだけ時間稼ぎをするから、とっとと村から出るなり好きにしろ。","ENG":"I'll buy you as much time as I can, so retreat to the village or wherever you want.","TWN":"我會儘量爭取時間，你們趕快離開村子。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"그게 너희들이 살 수 있는 유일한 방법이야.","JPN":"それがお前たちが生き残る唯一の方法だ。","ENG":"That's the only way you'll survive.","TWN":"這是你們唯一能活下去的方法！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"제길! 혼자서 영웅 놀이라도 하겠다는 거야 뭐야!","JPN":"くそ！　一人で英雄ごっこするつもりかよ！","ENG":"Dammit! I'm not letting you play hero by yourself!","TWN":"可惡！怎麼能讓你一個人逞英雄！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"똥폼 잡고 죽을 생각이었다면 타이밍이 다르다고!","JPN":"カッコつけといて死ぬつもりなら、タイミングが悪すぎるんだよ！","ENG":"If you were thinking of dying like one, this isn't the right time!","TWN":"就是啊！想一個人這麼死掉，也太卑鄙了！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"비참하게 죽더라도 모두 함께 죽는 거다!","JPN":"惨めに死ぬとしても、みんな一緒に死ぬんだ！","ENG":"Even if we're going to die miserably, we're in this together!","TWN":"即使要死也是一起死啊！安哥！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"퍼부을 수 있는 건 다 퍼부어!","JPN":"とにかく全て撃ちまくれ！","ENG":"Give them everything we've got!","TWN":"好！那就打起一百二十分精神來！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"침식체를 마을 밖으로 유도해야 한다!","JPN":"侵食体を村の外まではじき出さないといけない！","ENG":"Lure the C.O.s out of the village!","TWN":"必須把侵蝕體引出村外！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마을안에서 날뛰게 해선 안 돼!","JPN":"村の中で暴れさせてはまずい！","ENG":"We mustn't let them run wild in the village!","TWN":"不能讓它們破壞我們的村子！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ff3636>바보… 꿈도 크네?</color>","JPN":"<color=#ff3636>バカ……夢がデカいね。</color>","ENG":"<color=#ff3636>Fools... How ambitious</color>.","TWN":"<color=#ff3636>愚蠢……在做夢嗎？</color>"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"순순히 마을 밖에 나가줄 리가 없잖아?","JPN":"素直に村から出てあげるわけないでしょう？","ENG":"They are not going to be lured that easily.","TWN":"你以為我會讓你們這麼做嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"네, 네년은…!","JPN":"き、貴様は……！","ENG":"Y-you are...!","TWN":"你……！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"걱정하지 마. 지금은 얌전히 보고만 있을게.","JPN":"心配しないで。今は大人しく見てるだけだから。","ENG":"Don't be frightened. I'll just watch for now.","TWN":"別擔心，我會乖乖地看著的。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"당장이라도 언니들의 복수를 해주고 싶지만….","JPN":"今すぐにでも姉さんたちの復讐をしてあげたいけど……","ENG":"I would love to avenge Eva and Mavka right now, but...","TWN":"雖然我很想立刻為姊姊們報仇……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흐~응. 그런 고물로는 내 몸에 흠집하나 낼 수 없어.","JPN":"ふーん。そんな古鉄じゃあ私の体に傷一つつけられないよ。","ENG":"Pfft. You can't even scratch me with that junk.","TWN":"哼～就憑那種破銅爛鐵，連我的身體都劃不破。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그래도 화내진 않을게. 언니들을 파괴한 당신들의 복수는….","JPN":"でも、怒らないからね。姉さんたちを破壊したあなたたちへの復讐は……","ENG":"But I won't get mad. Because those children will take revenge…","TWN":"不過我不會生氣。因為傷害姊姊們的仇……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저 아이들이 대신해 줄 거니까.","JPN":"あの子どもたちが代わりにやってくれるから。","ENG":"for your killing my sisters.","TWN":"那些孩子們會替我報的。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"아이들이라고…?","JPN":"子どもたちだと……？","ENG":"Children...?","TWN":"孩子……？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};